<!doctype html><html lang="pt-BR"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>EditorVideoIA Templates</title>
<style>
*{box-sizing:border-box}body{margin:0;background:#0f172a;color:#e5e7eb;font-family:Arial,Helvetica,sans-serif;padding:24px}a{color:inherit;text-decoration:none}.page-head{display:flex;justify-content:space-between;align-items:center;gap:20px;margin-bottom:22px}.page-head h1{margin:0;font-size:30px}.page-head p,.muted{color:#94a3b8}.btn{display:inline-flex;align-items:center;justify-content:center;border:0;border-radius:10px;background:#334155;color:#fff;padding:11px 15px;font-weight:700;cursor:pointer}.btn.primary,.primary{background:#2563eb}.btn.danger,.danger{background:#dc2626}.ok{background:#064e3b;color:#bbf7d0;padding:14px;border-radius:12px;margin-bottom:16px}.grid{display:grid;grid-template-columns:minmax(320px,520px) 1fr;gap:22px}.card,.template-card,.empty{background:#111827;border:1px solid #334155;border-radius:18px;padding:20px}.form-card label{display:block;margin-top:13px;margin-bottom:6px;color:#cbd5e1;font-weight:700}.form-card input,.form-card select{width:100%;padding:12px;border-radius:10px;border:1px solid #475569;background:#020617;color:#fff}.actions{display:flex;gap:10px;margin-top:18px;align-items:center}.preview-card h2{margin-top:0}.canvas{width:360px;height:640px;max-width:100%;margin:auto;border-radius:24px;border:1px solid #475569;position:relative;overflow:hidden;background:#020617;box-shadow:0 20px 60px #0008}.preview-text{position:absolute;left:24px;right:24px;text-align:center;font-size:34px;font-weight:900;text-shadow:0 3px 10px #000}.preview-cta{position:absolute;left:45px;right:45px;border-radius:999px;padding:15px;text-align:center;font-size:24px;font-weight:900}.preview-subtitle{position:absolute;left:24px;right:24px;bottom:105px;text-align:center;font-size:20px;font-weight:800;text-shadow:0 3px 10px #000}.preview-watermark{position:absolute;font-size:15px;color:#fff9;background:#0006;padding:7px 10px;border-radius:999px}.pos-top{top:80px}.pos-center{top:280px}.pos-bottom{bottom:175px}.preview-cta.pos-top{top:30px}.preview-cta.pos-center{top:360px}.preview-cta.pos-bottom{bottom:40px}.wm-top-left{top:15px;left:15px}.wm-top-right{top:15px;right:15px}.wm-bottom-left{bottom:15px;left:15px}.wm-bottom-right{bottom:15px;right:15px}.cards{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:18px}.template-card h2{margin:12px 0 4px}.template-card p{color:#94a3b8}.mini{height:320px;border-radius:18px;position:relative;padding:24px;display:flex;align-items:center;justify-content:center;text-align:center;border:1px solid #475569;overflow:hidden}.mini strong{font-size:25px}.mini span{position:absolute;bottom:35px;padding:10px 18px;border-radius:999px;color:#111827;font-weight:900}.mini em{position:absolute;right:14px;bottom:12px;color:#fff9}.pagination{margin-top:18px}@media(max-width:900px){.grid,.page-head{display:block}.preview-card{margin-top:20px}}
</style></head><body>
